const airtable = $json ?? {};
const odoo = $('Normalize Odoo Delivery').first().json ?? {};
const errors = [];

if (airtable.workflowRevision !== 'WL-ATTACHMENTS-V5.4') {
  errors.push(`Unexpected Airtable workflow revision: ${airtable.workflowRevision ?? 'MISSING'}`);
}
if (odoo.workflowRevision !== 'WL-ATTACHMENTS-V5.4') {
  errors.push(`Unexpected Odoo workflow revision: ${odoo.workflowRevision ?? 'MISSING'}`);
}
if (airtable.airtableStatus !== 'success' || !airtable.airtableRecordId) {
  errors.push(`Airtable write failed: ${airtable.airtableError ?? 'record ID missing'}`);
}
if (airtable.airtableNativeAttachmentCount !== airtable.expectedAttachmentCount) {
  errors.push(`Airtable native attachment count mismatch: expected ${airtable.expectedAttachmentCount}, received ${airtable.airtableNativeAttachmentCount ?? 'UNKNOWN'}`);
}
if (odoo.odooStatus !== 'success' || !odoo.odooWebLeadId) {
  errors.push(`Odoo delivery failed (HTTP ${odoo.odooHttpStatus ?? 'UNKNOWN'}): ${odoo.odooError ?? 'web_lead_id missing'}`);
}

if (errors.length) {
  throw new Error(`WL-ATTACHMENTS-V5.4 final production gate failed: ${errors.join(' | ')}`);
}

return {
  json: {
    workflowRevision: 'WL-ATTACHMENTS-V5.4',
    status: 'success',
    leadId: airtable.leadId,
    airtableRecordId: airtable.airtableRecordId,
    airtableNativeAttachmentCount: airtable.airtableNativeAttachmentCount,
    odooStatus: odoo.odooStatus,
    odooHttpStatus: odoo.odooHttpStatus,
    odooWebLeadId: odoo.odooWebLeadId,
    odooLeadId: odoo.odooLeadId,
    odooDecision: odoo.odooDecision,
    odooState: odoo.odooState,
  },
};

const body = $('Webhook').first().json.body ?? {};
const rawFiles = body.UploadPhotosOfYourScrapUpTo10;

if (!Array.isArray(rawFiles)) {
  throw new Error('Cognito attachment field UploadPhotosOfYourScrapUpTo10 is not an array.');
}
if (rawFiles.length === 0) {
  throw new Error('Cognito submission contains no attachments.');
}
if (rawFiles.length > 10) {
  throw new Error(`Cognito submission contains ${rawFiles.length} attachments; maximum supported is 10.`);
}

const seen = new Set();
const expectedAttachmentCount = rawFiles.length;
const entryNumber = body.Entry?.Number;
if (!entryNumber) {
  throw new Error('Cognito submission is missing Entry.Number.');
}
const leadId = `WL${entryNumber}`;

return rawFiles.map((file, attachmentIndex) => {
  if (!file || typeof file !== 'object') {
    throw new Error(`Attachment ${attachmentIndex + 1} is not a valid file object.`);
  }

  const originalFileName = String(file.Name ?? '').trim();
  const sourceDownloadUrl = String(file.File ?? '').trim();
  const sourceFileId = String(file.Id ?? '').trim();
  const contentType = String(file.ContentType ?? '').trim();
  const sizeBytes = Number(file.Size ?? 0);

  if (!sourceFileId) {
    throw new Error(`Attachment ${attachmentIndex + 1} is missing its Cognito file ID.`);
  }
  if (!originalFileName) {
    throw new Error(`Attachment ${attachmentIndex + 1} is missing its original filename.`);
  }
  if (!sourceDownloadUrl || !sourceDownloadUrl.startsWith('https://')) {
    throw new Error(`Attachment ${attachmentIndex + 1} (${originalFileName}) has an invalid download URL.`);
  }
  if (!contentType) {
    throw new Error(`Attachment ${attachmentIndex + 1} (${originalFileName}) is missing ContentType.`);
  }
  if (!Number.isInteger(sizeBytes) || sizeBytes <= 0) {
    throw new Error(`Attachment ${attachmentIndex + 1} (${originalFileName}) has an invalid size.`);
  }
  if (seen.has(sourceFileId)) {
    throw new Error(`Duplicate Cognito source file ID detected: ${sourceFileId}.`);
  }
  seen.add(sourceFileId);

  return {
    json: {
      workflowRevision: 'WL-ATTACHMENTS-V5.4',
      leadId,
      expectedAttachmentCount,
      attachmentIndex,
      sourceFileId,
      storageIdentity: sourceFileId,
      originalFileName,
      contentType,
      sizeBytes,
      sourceDownloadUrl,
    },
    pairedItem: { item: 0 },
  };
});

const input = $input.item;
const meta = input.json ?? {};
const binaryData = input.binary?.data;

if (!meta.sourceFileId || !meta.originalFileName || !meta.contentType) {
  throw new Error('Canonical attachment metadata is incomplete before binary restoration.');
}
if (!binaryData) {
  throw new Error(`Downloaded binary data is missing for ${meta.originalFileName}.`);
}
if (Number(binaryData.bytes ?? 0) !== Number(meta.sizeBytes)) {
  throw new Error(`Downloaded byte count mismatch for ${meta.originalFileName}: expected ${meta.sizeBytes}, received ${binaryData.bytes ?? 'UNKNOWN'}.`);
}

return {
  json: { ...meta },
  binary: {
    ...(input.binary ?? {}),
    data: {
      ...binaryData,
      fileName: meta.originalFileName,
      mimeType: meta.contentType,
    },
  },
  pairedItem: input.pairedItem ?? { item: $itemIndex },
};

const joined = $json ?? {};
const source = $('Restore Original Filename').item.json;

if (!source || joined.sourceFileId !== source.sourceFileId) {
  throw new Error(`Current loop source mismatch: joined=${joined.sourceFileId ?? 'UNKNOWN'}, source=${source?.sourceFileId ?? 'UNKNOWN'}.`);
}
if (joined.uploadStatus !== 'success' || !joined.driveFileId) {
  throw new Error(`Attachment upload is incomplete for ${source.originalFileName}.`);
}
if (!['success', 'failed', 'unsupported'].includes(joined.analysisStatus)) {
  throw new Error(`Attachment ${source.originalFileName} has an invalid analysis status.`);
}
if (joined.driveFileName !== source.originalFileName) {
  throw new Error(`Attachment filename changed after upload: ${source.originalFileName} -> ${joined.driveFileName}.`);
}
if (joined.driveMimeType !== source.contentType) {
  throw new Error(`Attachment MIME changed after upload for ${source.originalFileName}.`);
}

return {
  json: {
    workflowRevision: 'WL-ATTACHMENTS-V5.4',
    leadId: source.leadId,
    expectedAttachmentCount: source.expectedAttachmentCount,
    attachmentIndex: source.attachmentIndex,
    sourceFileId: source.sourceFileId,
    originalFileName: source.originalFileName,
    contentType: source.contentType,
    sizeBytes: source.sizeBytes,
    driveFileId: joined.driveFileId,
    driveFileName: joined.driveFileName,
    driveMimeType: joined.driveMimeType,
    driveSizeBytes: joined.driveSizeBytes,
    driveViewUrl: joined.driveViewUrl,
    driveDownloadUrl: joined.driveDownloadUrl,
    driveShared: joined.driveShared,
    uploadStatus: joined.uploadStatus,
    analysisType: joined.analysisType,
    analysisStatus: joined.analysisStatus,
    analysisData: joined.analysisData,
    analysisText: joined.analysisText,
    analysisError: joined.analysisError,
    airtableAttachment: {
      url: joined.driveDownloadUrl,
      filename: source.originalFileName,
    },
  },
};

const rows = Array.isArray($json.data) ? $json.data : [];
const rawFiles = $('Webhook').first().json.body?.UploadPhotosOfYourScrapUpTo10;
const expectedAttachmentCount = Array.isArray(rawFiles) ? rawFiles.length : 0;

if (rows.length !== expectedAttachmentCount) {
  throw new Error(`Attachment completeness check failed: expected ${expectedAttachmentCount}, received ${rows.length}.`);
}

const ordered = [...rows].sort((a, b) => a.attachmentIndex - b.attachmentIndex);
const sourceIds = new Set();
const driveIds = new Set();
const indexes = new Set();

for (let expectedIndex = 0; expectedIndex < ordered.length; expectedIndex++) {
  const row = ordered[expectedIndex];
  if (row.workflowRevision !== 'WL-ATTACHMENTS-V5.4') throw new Error(`Revision marker missing for ${row.originalFileName ?? 'UNKNOWN'}.`);
  if (row.attachmentIndex !== expectedIndex) throw new Error(`Attachment indexes are not contiguous at position ${expectedIndex}.`);
  if (!row.sourceFileId || sourceIds.has(row.sourceFileId)) throw new Error(`Missing or duplicate sourceFileId: ${row.sourceFileId ?? 'UNKNOWN'}.`);
  if (!row.driveFileId || driveIds.has(row.driveFileId)) throw new Error(`Missing or duplicate Drive file ID for ${row.originalFileName}.`);
  if (indexes.has(row.attachmentIndex)) throw new Error(`Duplicate attachment index: ${row.attachmentIndex}.`);
  if (row.uploadStatus !== 'success') throw new Error(`Upload failed for ${row.originalFileName}.`);
  if (!row.airtableAttachment?.url || row.airtableAttachment.filename !== row.originalFileName) {
    throw new Error(`Invalid Airtable attachment object for ${row.originalFileName}.`);
  }
  if (!['success', 'failed', 'unsupported'].includes(row.analysisStatus)) {
    throw new Error(`Missing or invalid analysis status for ${row.originalFileName}.`);
  }
  if (row.analysisStatus === 'failed' && !row.analysisError?.message) {
    throw new Error(`Failed analysis is missing an error message for ${row.originalFileName}.`);
  }
  sourceIds.add(row.sourceFileId);
  driveIds.add(row.driveFileId);
  indexes.add(row.attachmentIndex);
}

const successfulAnalysisCount = ordered.filter((row) => row.analysisStatus === 'success').length;
const failedAnalysisCount = ordered.filter((row) => row.analysisStatus === 'failed').length;
const unsupportedAnalysisCount = ordered.filter((row) => row.analysisStatus === 'unsupported').length;

return [{
  json: {
    workflowRevision: 'WL-ATTACHMENTS-V5.4',
    expectedAttachmentCount,
    successfulAttachmentCount: ordered.length,
    successfulUploadCount: ordered.filter((row) => row.uploadStatus === 'success').length,
    successfulAnalysisCount,
    failedAnalysisCount,
    unsupportedAnalysisCount,
    attachmentAnalysis: ordered.map((row) => ({
      filename: row.originalFileName,
      content_type: row.contentType,
      analysis_type: row.analysisType,
      analysis_status: row.analysisStatus,
      analysis_data: row.analysisData,
      analysis_text: row.analysisText,
      analysis_error: row.analysisError,
    })),
    airtableAttachments: ordered.map((row) => row.airtableAttachment),
    analysisWarnings: ordered.filter((row) => row.analysisStatus === 'failed').map((row) => ({ filename: row.originalFileName, error: row.analysisError?.message ?? 'UNKNOWN ERROR' })),
    attachmentManifest: ordered.map((row) => ({
      attachmentIndex: row.attachmentIndex,
      sourceFileId: row.sourceFileId,
      originalFileName: row.originalFileName,
      contentType: row.contentType,
      sizeBytes: row.sizeBytes,
      driveFileId: row.driveFileId,
      driveViewUrl: row.driveViewUrl,
      uploadStatus: row.uploadStatus,
      analysisStatus: row.analysisStatus,
    })),
  },
}];

const meta = $('Restore Original Filename').item.json;
const uploaded = $json ?? {};
const driveFileId = String(uploaded.id ?? '').trim();
const driveFileName = String(uploaded.name ?? '').trim();
const driveMimeType = String(uploaded.mimeType ?? '').trim();
const driveSizeBytes = Number(uploaded.size ?? 0);

if (!driveFileId) throw new Error(`Google Drive returned no file ID for ${meta.originalFileName}.`);
if (driveFileName !== meta.originalFileName) {
  throw new Error(`Drive filename mismatch for ${meta.sourceFileId}: expected "${meta.originalFileName}", received "${driveFileName}".`);
}
if (driveMimeType !== meta.contentType) {
  throw new Error(`Drive MIME mismatch for ${meta.originalFileName}: expected ${meta.contentType}, received ${driveMimeType}.`);
}
if (driveSizeBytes !== Number(meta.sizeBytes)) {
  throw new Error(`Drive size mismatch for ${meta.originalFileName}: expected ${meta.sizeBytes}, received ${uploaded.size ?? 'UNKNOWN'}.`);
}

return {
  json: {
    sourceFileId: meta.sourceFileId,
    driveFileId,
    driveFileName,
    driveMimeType,
    driveSizeBytes,
    driveViewUrl: uploaded.webViewLink || `https://drive.google.com/file/d/${driveFileId}/view`,
    driveDownloadUrl: `https://drive.google.com/uc?export=download&id=${encodeURIComponent(driveFileId)}`,
    uploadStatus: 'success',
    driveShared: Boolean(uploaded.shared),
  },
  pairedItem: $input.item.pairedItem ?? { item: $itemIndex },
};

const meta = $('Restore Original Filename').item.json;
const raw = $json ?? {};
const providerError = raw.error ? String(raw.error) : null;
let text = typeof raw.content === 'string' ? raw.content : null;
let parsed = null;

if (text) {
  const cleaned = text.trim().replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '');
  try { parsed = JSON.parse(cleaned); } catch { parsed = { raw_text: text }; }
}

const failed = Boolean(providerError) || !text;
return {
  json: {
    sourceFileId: meta.sourceFileId,
    analysisType: 'image',
    analysisStatus: failed ? 'failed' : 'success',
    analysisData: failed ? null : parsed,
    analysisText: failed ? null : text,
    analysisError: failed ? {
      provider: 'openai',
      message: providerError || 'OpenAI image analysis returned no content.',
      retryable: false,
    } : null,
  },
  pairedItem: $input.item.pairedItem ?? { item: $itemIndex },
};

return {
  json: {
    sourceFileId: $json.sourceFileId,
    analysisType: 'unsupported',
    analysisStatus: 'unsupported',
    analysisData: null,
    analysisText: null,
    analysisError: null,
  },
  pairedItem: $input.item.pairedItem ?? { item: $itemIndex },
};

const meta = $('Restore Original Filename').item.json;
const raw = $json ?? {};
const providerError = raw.error ? String(raw.error) : null;
let text = typeof raw.text === 'string' ? raw.text.trim() : null;
let parsed = null;

if (text) {
  const cleaned = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '');
  try { parsed = JSON.parse(cleaned); } catch { parsed = { raw_text: text }; }
}

const failed = Boolean(providerError) || !text;
return {
  json: {
    sourceFileId: meta.sourceFileId,
    analysisType: 'document',
    analysisStatus: failed ? 'failed' : 'success',
    analysisData: failed ? null : parsed,
    analysisText: failed ? null : text,
    analysisError: failed ? {
      provider: 'openai',
      stage: 'pdf-text-analysis',
      message: providerError || 'OpenAI PDF text analysis returned no content.',
      retryable: false,
    } : null,
  },
  pairedItem: $input.item.pairedItem ?? { item: $itemIndex },
};

const meta = $('Restore Original Filename').item.json;
const raw = $json ?? {};
return {
  json: {
    sourceFileId: meta.sourceFileId,
    analysisType: 'document',
    analysisStatus: 'failed',
    analysisData: null,
    analysisText: null,
    analysisError: {
      provider: 'n8n-pdf-extractor',
      stage: 'pdf-text-extraction',
      message: raw.error ? String(raw.error) : 'PDF contains no extractable text. Scanned-document fallback is not enabled in this revision.',
      retryable: false,
    },
  },
  pairedItem: $input.item.pairedItem ?? { item: $itemIndex },
};

const bodyInput = $('Webhook').first().json.body ?? {};
const entryNumber = bodyInput.Entry?.Number;
const leadId = `WL${entryNumber}`;
const raw = $json ?? {};
const statusCode = Number(raw.statusCode ?? raw.status ?? raw.httpCode ?? 0) || null;
let body = raw.body;
if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch { body = { message: body }; }
}
if (!body || typeof body !== 'object' || Array.isArray(body)) body = raw;

const success = Boolean(
  statusCode && statusCode >= 200 && statusCode < 300 &&
  body.status === 'ok' && body.web_lead_id
);
const message = success
  ? null
  : String(
      body.message ??
      body.error ??
      raw.error?.message ??
      raw.error ??
      raw.message ??
      `Unexpected Odoo response (HTTP ${statusCode ?? 'UNKNOWN'}).`
    );

return {
  json: {
    workflowRevision: 'WL-ATTACHMENTS-V5.4',
    leadId,
    cognitoEntryNumber: entryNumber ?? null,
    odooStatus: success ? 'success' : 'failed',
    odooHttpStatus: statusCode,
    odooWebLeadId: body.web_lead_id ?? null,
    odooLeadId: body.lead_id ?? null,
    odooDecision: body.decision ?? null,
    odooState: body.state ?? null,
    odooIntakeId: body.intake_id ?? null,
    odooPartnerId: body.partner_id ?? null,
    odooResponse: body,
    odooError: success ? null : message,
  },
};

const finalized = $('Finalize Attachment Batch').first().json;
const entryNumber = $('Webhook').first().json.body?.Entry?.Number;
const leadId = `WL${entryNumber}`;
const raw = $json ?? {};
const fields = raw.fields && typeof raw.fields === 'object' ? raw.fields : {};
const nativeAttachments = Array.isArray(fields.Attachments) ? fields.Attachments : null;
const recordId = String(raw.id ?? '').trim();

return {
  json: {
    workflowRevision: 'WL-ATTACHMENTS-V5.4',
    leadId,
    airtableStatus: recordId ? 'success' : 'failed',
    airtableRecordId: recordId || null,
    airtableCreatedTime: raw.createdTime ?? null,
    airtableNativeAttachmentCount: nativeAttachments ? nativeAttachments.length : null,
    expectedAttachmentCount: finalized.expectedAttachmentCount,
    airtableResponse: raw,
    airtableError: recordId ? null : String(raw.error ?? 'Airtable returned no record ID.'),
  },
};

const airtable = $json ?? {};
const odoo = $('Normalize Odoo Delivery').first().json ?? {};
const errors = [];

if (airtable.workflowRevision !== 'WL-ATTACHMENTS-V5.4') {
  errors.push(`Unexpected Airtable workflow revision: ${airtable.workflowRevision ?? 'MISSING'}`);
}
if (odoo.workflowRevision !== 'WL-ATTACHMENTS-V5.4') {
  errors.push(`Unexpected Odoo workflow revision: ${odoo.workflowRevision ?? 'MISSING'}`);
}
if (airtable.airtableStatus !== 'success' || !airtable.airtableRecordId) {
  errors.push(`Airtable write failed: ${airtable.airtableError ?? 'record ID missing'}`);
}
if (airtable.airtableNativeAttachmentCount !== airtable.expectedAttachmentCount) {
  errors.push(`Airtable native attachment count mismatch: expected ${airtable.expectedAttachmentCount}, received ${airtable.airtableNativeAttachmentCount ?? 'UNKNOWN'}`);
}
if (odoo.odooStatus !== 'success' || !odoo.odooWebLeadId) {
  errors.push(`Odoo delivery failed (HTTP ${odoo.odooHttpStatus ?? 'UNKNOWN'}): ${odoo.odooError ?? 'web_lead_id missing'}`);
}

if (errors.length) {
  throw new Error(`WL-ATTACHMENTS-V5.4 final production gate failed: ${errors.join(' | ')}`);
}

return {
  json: {
    workflowRevision: 'WL-ATTACHMENTS-V5.4',
    status: 'success',
    leadId: airtable.leadId,
    airtableRecordId: airtable.airtableRecordId,
    airtableNativeAttachmentCount: airtable.airtableNativeAttachmentCount,
    odooStatus: odoo.odooStatus,
    odooHttpStatus: odoo.odooHttpStatus,
    odooWebLeadId: odoo.odooWebLeadId,
    odooLeadId: odoo.odooLeadId,
    odooDecision: odoo.odooDecision,
    odooState: odoo.odooState,
  },
};

const raw = $json ?? {};
const form = $('Webhook').first().json.body ?? {};
const batch = $('Finalize Attachment Batch').first().json ?? {};
const clone = (value) => JSON.parse(JSON.stringify(value ?? {}));
const output = raw.output && typeof raw.output === 'object' ? clone(raw.output) : {};
const fallbackUsed = !raw.output || typeof raw.output !== 'object';
const normalized = output.normalized && typeof output.normalized === 'object' ? clone(output.normalized) : {};
const rows = Array.isArray(batch.attachmentAnalysis) ? batch.attachmentAnalysis : [];
const successfulImages = rows.filter((row) => row.analysis_type === 'image' && row.analysis_status === 'success' && row.analysis_data).map((row) => row.analysis_data);
const successfulDocs = rows.filter((row) => row.analysis_type === 'document' && row.analysis_status === 'success' && row.analysis_data).map((row) => row.analysis_data);
const failedAnalyses = rows.filter((row) => row.analysis_status === 'failed');
const lower = (value) => String(value ?? '').toLowerCase();
const joined = (...values) => values.flat(Infinity).filter((v) => v !== null && v !== undefined).map((v) => typeof v === 'object' ? JSON.stringify(v) : String(v)).join(' ');
const formText = joined(form.WhatIsIt, form.WhatMaterialIsItMadeFrom, form.AreThereAnyContaminants);
const imageText = joined(successfulImages);
const documentText = joined(successfulDocs);
const allEvidence = lower(joined(formText, imageText, documentText));
const imageColorEvidence = lower(joined(successfulImages.map((d) => d.color), successfulImages.map((d) => d.notes)));
const corrections = [];
const reasons = Array.isArray(output.reasons) ? [...output.reasons] : [];
let clarifications = Array.isArray(output.clarification_requests) ? [...output.clarification_requests] : [];

const parseWeight = (value) => {
  if (typeof value === 'number' && Number.isFinite(value) && value > 0) return value;
  const text = String(value ?? '').replace(/,/g, '');
  const matches = [...text.matchAll(/(?:^|\D)(\d+(?:\.\d+)?)(?=\D|$)/g)].map((m) => Number(m[1])).filter((n) => Number.isFinite(n) && n > 0);
  return matches.length ? Math.max(...matches) : 0;
};
const agentWeight = parseWeight(normalized.per_load_qty_lbs);
const quantityWeight = parseWeight(form.WhatIsTheQuantity);
const formWeight = parseWeight(form.WeightPerLoad);
const weight = agentWeight || quantityWeight || formWeight || 0;
const businessPresent = Boolean(String(form.YourBusinessCompanyName ?? '').trim());
const plasticPresent = /plastic|bopp|polypropylene|polyethylene|hdpe|ldpe|lldpe|pet|pvc|ps|abs|nylon|acrylic/i.test(joined(form.WhatMaterialIsItMadeFrom, form.WhatIsIt, documentText));

if (/\bbopp\b|biaxially oriented polypropylene|poly\s*\(propylene\)|\bpolypropylene\b/i.test(joined(form.WhatIsIt, documentText))) {
  if (normalized.polymer !== 'PP') corrections.push(`polymer:${normalized.polymer ?? 'MISSING'}->PP`);
  normalized.polymer = 'PP';
}

if (/trim scrap|edge trim|production scrap|off[- ]?spec|purge|sprues?|runners?/i.test(joined(form.WhatIsIt))) {
  if (normalized.type !== 'Post Industrial') corrections.push(`type:${normalized.type ?? 'MISSING'}->Post Industrial`);
  normalized.type = 'Post Industrial';
}

const cleanlinessText = lower(form.AreThereAnyContaminants);
if (/\bclean\b/.test(cleanlinessText) && !/not clean|unclean/.test(cleanlinessText)) normalized.cleanliness = 'Clean';
else if (/minor|mixed|some contamination/.test(cleanlinessText)) normalized.cleanliness = 'Mixed';
else if (/dirty|heavy contamination|contaminated/.test(cleanlinessText)) normalized.cleanliness = 'Dirty';

const baleImageCount = successfulImages.filter((d) => /\bbales?\b|\bbaled\b|tightly compressed/i.test(joined(d.physical_form, d.packaging, d.quantity_observation, d.notes))).length;
const explicitAlternativePackaging = successfulImages.filter((d) => /\bgaylords?\b|\bsupersacks?\b|\bcrates?\b|\bloose\b/i.test(joined(d.packaging))).length;
const baleConfirmed = baleImageCount >= 2 && explicitAlternativePackaging === 0;
const filmConfirmed = /\bfilm\b|\bbopp\b/i.test(joined(form.WhatIsIt, documentText, successfulImages.map((d) => d.physical_form)));

if (baleConfirmed) {
  if (normalized.packaging !== 'Bales') corrections.push(`packaging:${normalized.packaging ?? 'MISSING'}->Bales`);
  normalized.packaging = 'Bales';
  if (filmConfirmed) {
    if (normalized.form !== 'Film Bales') corrections.push(`form:${normalized.form ?? 'MISSING'}->Film Bales`);
    normalized.form = 'Film Bales';
  }
}

if (/multicolou?r|mixed|colored pieces|printed/i.test(joined(imageColorEvidence, form.WhatIsIt))) {
  if (normalized.color !== 'Mixed') corrections.push(`color:${normalized.color ?? 'MISSING'}->Mixed`);
  normalized.color = 'Mixed';
}

const enumMap = {
  polymer: ['PP','HDPE','LDPE','LLDPE','PET','PVC','PS','ABS','PC','Nylon','Acrylic','Other','Unclear'],
  form: ['Pellets','Regrind','Flake','Film Bales','Film Rolls','Logs/Agglo','Purge','Parts','Rigid Bales','Pallet Stacks','Loose','Floorsweep','Unclear'],
  type: ['Post Industrial','Post Commercial','Post Consumer','Virgin','Repro','Unclear'],
  color: ['Natural','Mixed','White','Black','Green','Blue','Red','Yellow','Gray','Custom','Unknown'],
  cleanliness: ['Clean','Mixed','Dirty','Unclear'],
  packaging: ['Bales','Supersacks','Gaylords','Loose','Crates','Other','Unclear'],
};
for (const [field, allowed] of Object.entries(enumMap)) {
  const fallback = field === 'color' ? 'Unknown' : 'Unclear';
  if (!allowed.includes(normalized[field])) {
    corrections.push(`${field}:${normalized[field] ?? 'MISSING'}->${fallback}`);
    normalized[field] = fallback;
  }
}

normalized.per_load_qty_lbs = weight;
normalized.loads_per_week = Number.isFinite(Number(normalized.loads_per_week)) ? Number(normalized.loads_per_week) : 0;
normalized.loads_per_month = Number.isFinite(Number(normalized.loads_per_month)) ? Number(normalized.loads_per_month) : 0;
normalized.origin_city = String(normalized.origin_city ?? form.LocationOfPickUpCityState ?? '').trim() || 'Unclear';
normalized.origin_state = String(normalized.origin_state ?? '').trim() || 'Unclear';

if (normalized.packaging !== 'Unclear') clarifications = clarifications.filter((q) => !/packaging|bales|gaylords|wrapped pallets/i.test(String(q)));
if (normalized.form !== 'Unclear') clarifications = clarifications.filter((q) => !/material considered|material form|film bales|regrind\/flake/i.test(String(q)));
if (!clarifications.some((q) => /ongoing|one-time|frequency/i.test(String(q)))) clarifications.push('Confirm if material is ongoing or a one-time load');
if (failedAnalyses.length && !clarifications.some((q) => /manual review.*attachment|attachment analysis/i.test(String(q)))) {
  clarifications.push(`Manual review required for ${failedAnalyses.length} attachment analysis failure(s)`);
}
clarifications = [...new Set(clarifications.map((q) => String(q).trim()).filter(Boolean))];

let decision = ['Hot','Unclear Hot','Cold'].includes(output.decision) ? output.decision : null;
let target = ['HOT','COLD'].includes(output.airtable_target) ? output.airtable_target : null;
if (!decision || !target) {
  if (weight > 0 && weight < 8000) {
    decision = 'Cold';
    target = 'COLD';
  } else if (weight >= 10000 && businessPresent && plasticPresent) {
    decision = 'Unclear Hot';
    target = 'HOT';
  } else {
    decision = 'Unclear Hot';
    target = 'HOT';
  }
}
if (decision === 'Unclear Hot') target = 'HOT';
if (decision === 'Cold') target = 'COLD';
if (decision === 'Hot') target = 'HOT';

if (baleConfirmed && filmConfirmed && !reasons.some((r) => /bale/i.test(String(r)))) reasons.push('Multiple images consistently confirm film material shipped in bales.');
if (fallbackUsed) reasons.push('Automated agent output was unavailable; deterministic safe-review normalization was applied.');
if (!reasons.length) reasons.push('Manual review required; deterministic normalization preserved the lead.');

let notes = String(normalized.notes ?? '').trim();
if (decision === 'Unclear Hot' && !/Unclear Classification/i.test(notes)) notes = `Unclear Classification; ${notes}`.replace(/;\s*$/, '');
if (corrections.length) notes = `${notes}${notes ? '; ' : ''}Evidence alignment applied: ${corrections.join(', ')}`;
if (failedAnalyses.length) notes = `${notes}${notes ? '; ' : ''}${failedAnalyses.length} attachment analysis failure(s) retained for manual review`;
normalized.notes = notes || 'Manual review required.';

return {
  json: {
    output: {
      decision,
      reasons: [...new Set(reasons.map((r) => String(r).trim()).filter(Boolean))],
      clarification_requests: clarifications,
      normalized,
      email_template: String(output.email_template ?? (target === 'HOT' ? 'Qualified A' : 'Rejection B')),
      airtable_target: target,
    },
    alignment: {
      workflowRevision: 'WL-ATTACHMENTS-V5.4',
      fallbackUsed,
      baleImageCount,
      baleConfirmed,
      filmConfirmed,
      failedAnalysisCount: failedAnalyses.length,
      corrections,
    },
  },
};
